+    #[test]
+    fn test_crash_recovery_noop_for_terminal_states() {
+        let mut mgr = EvictionSagaManager::new();
+        let id = mgr.start_saga("a", true, "t1").unwrap();
+        mgr.begin_upload(&id, "t2").unwrap();
